    "bibcode": "2020A&A...637A..53K",
    "title": "Hypervelocity Stars in the Gaia era. Revisiting the most extreme stars from the MMT survey",
    "month": "2020-03",
    "source_note_json": "notes/2020/2020-03/2020-03.json",
    "links": {
      "abs": "https://arxiv.org/abs/2003.12766",
      "pdf": "https://arxiv.org/pdf/2003.12766"
    }
  },
  "inputs": {
    "paper_dir": "literature/2003.12766",
    "audit_path": "literature/2003.12766/audit.json",
    "catalog_review_path": "literature/2003.12766/catalog_review.json",
    "catalog_extraction_path": "literature/2003.12766/catalog_extraction.json",
    "ecsv_paths": [
      "literature/2003.12766/catalog_tables/table-tab-atmos-results.ecsv",
      "literature/2003.12766/catalog_tables/table-tab-B1085.ecsv",
      "literature/2003.12766/catalog_tables/table-tab-hvs5.ecsv",
      "literature/2003.12766/catalog_tables/table-tab-stellar_params.ecsv",
      "literature/2003.12766/catalog_tables/table-tab-kinematic-AS.ecsv",
      "literature/2003.12766/catalog_tables/table-tab-kinematic-TF.ecsv"
    ]
  },
  "extraction": {
    "status": "candidates_found",
    "extracted_at": "2026-06-12T23:04:48",
    "extractor": "agent",
    "summary": "Paper reanalyzes 40 B-type stars from the MMT HVS survey, obtaining spectrophotometric distances and performing kinematic analysis for 37 of them. 25 stars are treated as possibly unbound: the 22 HVS-numbered stars (HVS1, HVS4–HVS24) and three originally bound stars that become unbound or ambiguous (B485, B1085, B576). 15 B-numbered stars are concluded to be likely bound and are excluded.",
    "tooling": null
  },
  "method_chain": [
    {
      "id": "step-01",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Input data: MMT HVS survey flux-calibrated spectra (Warren Brown), Gaia DR2 astrometry and photometry, HST proper motions for 15 stars, and photometric catalogs (GALEX, SDSS, Pan-STARRS1, Gaia, UKIDSS, VISTA, SkyMapper, etc.).",
      "inputs": [],
      "outputs": ["mmt_spectra", "gaia_dr2_astrometry", "hst_astrometry", "photometry_catalogs"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 99,
          "end_line": 99,
          "context": "In this work, which we regard as Paper~III in this series, we extend the spectrophotometric analysis to 40 out of the 42 high-velocity outliers of the MMT HVS sample."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 272,
          "end_line": 272,
          "context": "Photometric data were compiled from a variety of surveys covering the ultraviolet, the optical, and the infrared mainly using the VizieR catalog access tool."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "Proper motions were mainly taken from Gaia DR2. ... For a subsample of 15 stars, pre-Gaia proper motions measured with the HST instruments WFC3 and ACS were available."
        }
      ]
    },
    {
      "id": "step-02",
      "depends_on": [
        "step-01"
      ],
      "step_type": "cross_match",
      "summary": "Cross-match of MMT target list with Gaia DR2 and HST catalogs; when both Gaia and HST proper motions are available, the more precise measurement is selected (HST for HVS1, HVS10, HVS12, HVS13; Gaia for B711).",
      "inputs": ["mmt_target_list", "gaia_dr2_astrometry", "hst_astrometry"],
      "outputs": ["matched_proper_motions"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "Proper motions were mainly taken from Gaia DR2. ... For a subsample of 15 stars, pre-Gaia proper motions measured with the HST ... we chose the more precise measurement when Gaia as well as HST proper motions were available."
        }
      ]
    },
    {
      "id": "step-03",
      "depends_on": [
        "step-01"
      ],
      "step_type": "stellar_parameter_inference",
      "summary": "Spectroscopic analysis of flux-calibrated MMT spectra: simultaneous fit using χ² minimization to derive effective temperature T_eff, surface gravity log(g), and projected rotational velocity v sin(i). Atmospheric parameters from spectral lines; interstellar reddening E(B−V) included as fit parameter with R_V=3.1. Uses non-LTE model grid (Atlas12/Detail/Surface).",
      "inputs": ["mmt_spectra", "model_grid"],
      "outputs": ["T_eff", "log_g", "v_sin_i"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 132,
          "end_line": 150,
          "context": "The spectral analysis strategy basically followed Irrgang et al. (2014). ... We were thus left with four fitting parameters for the stellar spectrum: the effective temperature T_eff, the surface gravity log(g), the projected rotational velocity v sin(i), and the radial velocity v_rad."
        }
      ]
    },
    {
      "id": "step-03b",
      "depends_on": [
        "step-01"
      ],
      "step_type": "radial_velocity_measurement",
      "summary": "Radial velocity v_rad measured from the same spectral fitting process as step-03. The MMT spectra are fitted with the model grid, yielding radial velocity along with atmospheric parameters.",
      "inputs": ["mmt_spectra"],
      "outputs": ["v_rad"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 150,
          "end_line": 150,
          "context": "We were thus left with four fitting parameters for the stellar spectrum: the effective temperature T_eff, the surface gravity log(g), the projected rotational velocity v sin(i), and the radial velocity v_rad."
        }
      ]
    },
    {
      "id": "step-04",
      "depends_on": [
        "step-01",
        "step-03"
      ],
      "step_type": "photometric_or_sed_modeling",
      "summary": "SED fitting: Observed spectral energy distributions from compiled photometry compared to synthetic SEDs based on Atlas12 models with parameters fixed to spectroscopic values. Only angular diameter Θ and color excess E(B−V) are fitted.",
      "inputs": ["photometry_catalogs", "spectroscopic_parameters"],
      "outputs": ["angular_diameter", "E_B_V"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 276,
          "end_line": 276,
          "context": "The resulting observed SEDs were compared to synthetic ones based on Atlas12 model computations ... we were left with only two free fitting parameters, the angular diameter Θ as distance scaling factor and the color excess E(B−V) as indicator for interstellar reddening and extinction."
        }
      ]
    },
    {
      "id": "step-05",
      "depends_on": [
        "step-03",
        "step-04"
      ],
      "step_type": "distance_estimation",
      "summary": "Spectrophotometric distances: combine angular diameters Θ = 2 R / d with stellar radii R = (G M / g)^{1/2} from spectroscopic surface gravity and masses from evolutionary tracks (rotating MS models). Alternative distances for B598 (pre-ELM WD) and B576 (BHB) using typical masses.",
      "inputs": ["angular_diameter", "log_g", "evolutionary_mass"],
      "outputs": ["distance"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 280,
          "end_line": 281,
          "context": "The resulting angular diameters Θ = 2 R/d were combined with the stellar radii R = (G M/g)^{1/2} which are based on the surface gravities g from spectroscopy and the stellar masses derived from evolutionary tracks ... This allowed us to calculate the spectrophotometric distances d which are listed in Table 3."
        }
      ]
    },
    {
      "id": "step-06",
      "depends_on": [
        "step-02"
      ],
      "step_type": "quality_filter",
      "summary": "Astrometric quality filter: RUWE from Gaia DR2 < 1.4 for all objects, confirming well-behaved astrometric solutions. The more precise proper motion (Gaia or HST) is selected when both are available.",
      "inputs": ["gaia_dr2_astrometry"],
      "outputs": ["filtered_proper_motions"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "We used the 'renormalized unit weight error' (RUWE) ... as primary indicator for the quality of the astrometric solution. ... For all objects in the sample, RUWE is below the recommended value of 1.4, indicating that the astrometric solutions are well-behaved."
        }
      ]
    },
    {
      "id": "step-07",
      "depends_on": [],
      "step_type": "solar_position_and_motion",
      "summary": "Solar position and motion parameters (R0, z0, circular velocity at the Sun, solar peculiar motion U/V/W) are not reported in this paper; they are presumably taken from Paper II (2018A&A...620A..48I).",
      "inputs": [],
      "outputs": ["solar_parameters"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 293,
          "end_line": 293,
          "context": "The strategy of the kinematic analysis is identical to that of Paper II."
        }
      ]
    },
    {
      "id": "step-08",
      "depends_on": [
        "step-02",
        "step-03b",
        "step-05",
        "step-06",
        "step-07"
      ],
      "step_type": "velocity_calculation",
      "summary": "Transformation to right-handed Cartesian Galactic coordinate system (Sun on negative x-axis, z-axis to north). Compute Galactocentric positions (x,y,z) and velocities (v_x,v_y,v_z), Galactic rest-frame velocity v_Grf, and ejection velocities (accounting for Galactic rotation).",
      "inputs": ["proper_motions", "radial_velocity", "distance", "solar_parameters"],
      "outputs": ["galactocentric_positions", "galactocentric_velocities", "v_Grf"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 307,
          "end_line": 307,
          "context": "The quantities shown there are based on a right-handed Cartesian Galactic coordinate system in which the Sun is located on the negative x-axis and the z-axis points to the Galactic north pole."
        }
      ]
    },
    {
      "id": "step-09",
      "depends_on": [],
      "step_type": "galactic_potential_model",
      "summary": "Two Milky Way mass models: Model I (revision of Allen & Santillan 1991) and Model II (flat rotation curve model by Wilkinson & Evans 1999). Both calibrated with same observational constraints and consistent with Gaia DR2.",
      "inputs": [],
      "outputs": ["potential_models"],
      "parameters": [
        {
          "name": "potential_name",
          "raw_value": "Model I (revised Allen & Santillan 1991)",
          "value": "Model I",
          "source_refs": [
            {
              "kind": "text",
              "path": "literature/2003.12766/arxiv_source/aa.tex",
              "start_line": 293,
              "end_line": 293,
              "context": "Model I is a revision of the popular model by Allen & Santillan (1991) and Model II is based on the flat rotation curve model by Wilkinson & Evans (1999)."
            }
          ]
        },
        {
          "name": "potential_name",
          "raw_value": "Model II (flat rotation curve model by Wilkinson & Evans 1999)",
          "value": "Model II",
          "source_refs": [
            {
              "kind": "text",
              "path": "literature/2003.12766/arxiv_source/aa.tex",
              "start_line": 293,
              "end_line": 293,
              "context": "Model II is based on the flat rotation curve model by Wilkinson & Evans (1999)."
            }
          ]
        }
      ]
    },
    {
      "id": "step-10",
      "depends_on": [
        "step-08",
        "step-09",
        "step-03",
        "step-07"
      ],
      "step_type": "orbit_integration",
      "summary": "Backward orbit integration using a Monte Carlo approach (1.5 million realizations) for up to 15 Gyr. Uncertainties in distance, radial velocity, and proper motions are propagated. Orbits that cross the Galactic plane within the upper 99% confidence limit for the stellar age are retained.",
      "inputs": ["galactocentric_positions", "galactocentric_velocities", "potential_models", "stellar_age"],
      "outputs": ["orbit_properties", "plane_crossing_locations"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 284,
          "end_line": 284,
          "context": "The strategy of the kinematic analysis is identical to that of Paper II. Complementing our revised radial velocities and spectrophotometric distances with positions and proper motions ... gave us the full six-dimensional phase space information that is needed to calculate the trajectories of the program stars back in time to unravel their (spatial) origin. Propagation of uncertainties ... was achieved using a standard Monte Carlo approach with 1.5 million realizations."
        }
      ]
    },
    {
      "id": "step-11",
      "depends_on": [
        "step-08",
        "step-09",
        "step-10"
      ],
      "step_type": "escape_or_bound_assessment",
      "summary": "Compute local escape velocity v_esc from the Galactic potential, the escape velocity excess (v_Grf − v_esc), and the bound probability P_b (percentage) from Monte Carlo orbits.",
      "inputs": ["galactocentric_positions", "galactocentric_velocities", "potential_models", "orbit_properties"],
      "outputs": ["v_esc", "escape_excess", "P_b"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/AS.tex",
          "start_line": 6,
          "end_line": 7,
          "context": "Table header with P_b (%) column"
        }
      ]
    },
    {
      "id": "step-12",
      "depends_on": [
        "step-10",
        "step-03"
      ],
      "step_type": "origin_assessment",
      "summary": "Classify stars into origin categories (unconstrained, outer rim, disk origin) based on plane-crossing locations of Monte Carlo orbits; compare flight times to evolutionary ages; determine ejection velocities at plane crossing.",
      "inputs": ["plane_crossing_locations", "stellar_age"],
      "outputs": ["origin_category", "ejection_velocity"],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 322,
          "end_line": 322,
          "context": "In the following, we group the stars in three categories based on their inferred spatial origin."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 297,
          "end_line": 297,
          "context": "Tracing back the trajectories of the targets also gave us information about their spatial origin within the Galactic plane."
        }
      ]
    }
  ],
